class Solution:
    def maxFreq(self, s: str, maxLetters: int, minSize: int, maxSize: int) -> int:
        res = 0
        for size in range(minSize, maxSize + 1):
            freq = {}
            for i in range(len(s) - size + 1):
                sub = s[i:i + size]
                if len(set(sub)) <= maxLetters:
                    freq[sub] = freq.get(sub, 0) + 1
                    res = max(res, freq[sub])
        return res
